import { useMemo, useState } from "react";
import {
  FaUserCircle,
  FaShoppingBag,
  FaClipboardList,
  FaBell,
  FaUserShield,
  FaSignOutAlt,
  FaArrowTrendUp,
  FaCheckCircle,
  FaClock,
  FaShieldAlt,
  FaRocket,
} from "react-icons/fa6";

import { useAuth } from "../context/AuthContext";
import Navbar from "../components/Navbar";
import Sidebar from "../components/Sidebar";
import Loader from "../components/Loader";
import ErrorMessage from "../components/ErrorMessage";

function Dashboard() {
  const { token, user, logout, loading } = useAuth();
  const [apiError, setApiError] = useState("");

  const stats = useMemo(
    () => [
      {
        title: "Orders",
        value: "128",
        icon: <FaShoppingBag />,
        color: "blue",
      },
      {
        title: "Notifications",
        value: "14",
        icon: <FaBell />,
        color: "purple",
      },
      {
        title: "Profile Score",
        value: "96%",
        icon: <FaUserShield />,
        color: "green",
      },
      {
        title: "Security",
        value: "Secure",
        icon: <FaShieldAlt />,
        color: "orange",
      },
    ],
    []
  );

  const activities = [
    {
      title: "Successfully logged in",
      time: "Just now",
      icon: <FaCheckCircle />,
    },
    {
      title: "JWT Token Validated",
      time: "2 mins ago",
      icon: <FaShieldAlt />,
    },
    {
      title: "Dashboard Opened",
      time: "5 mins ago",
      icon: <FaRocket />,
    },
    {
      title: "Axios Authorization Ready",
      time: "10 mins ago",
      icon: <FaClock />,
    },
  ];

  const quickActions = [
    {
      title: "Profile",
      icon: <FaUserCircle />,
    },
    {
      title: "Orders",
      icon: <FaClipboardList />,
    },
    {
      title: "Notifications",
      icon: <FaBell />,
    },
    {
      title: "Analytics",
      icon: <FaArrowTrendUp />,
    },
  ];

  const handleLogout = () => {
    if (window.confirm("Do you really want to logout?")) {
      try {
        logout();
      } catch (e) {
        setApiError("Logout failed. Please try again.");
      }
    }
  };

  if (loading) {
    return <Loader text="Loading Dashboard..." />;
  }

  return (
    <div className="app-shell">
      <Navbar />
      <Sidebar />

      <main className="dashboard-main">

        {/* HERO */}

        <section className="dashboard-hero">

          <div className="hero-left">

            <div className="hero-avatar">
              {user?.name?.charAt(0)?.toUpperCase() || "U"}
            </div>

            <div>

              <h1>
                Welcome Back,
                <span> {user?.name || "User"} 👋</span>
              </h1>

              <p>
                Have a productive day! Everything is running smoothly.
              </p>

            </div>

          </div>

          <div className="hero-right">

            <div className="hero-date">
              {new Date().toLocaleDateString()}
            </div>

            <button
              className="logout-modern-btn"
              onClick={handleLogout}
            >
              <FaSignOutAlt />
              Logout
            </button>

          </div>

        </section>

        {/* STATISTICS */}

        <section className="stats-grid">

          {stats.map((item) => (

            <div
              key={item.title}
              className={`stats-card ${item.color}`}
            >

              <div className="stats-icon">
                {item.icon}
              </div>

              <div>

                <h2>{item.value}</h2>

                <p>{item.title}</p>

              </div>

            </div>

          ))}

        </section>

        {/* CONTENT */}

        <section className="dashboard-content">

          {/* LEFT */}

          <div className="dashboard-left">

            {/* Quick Actions */}

            <div className="modern-card">

              <div className="card-title">
                Quick Actions
              </div>

              <div className="quick-grid">

                {quickActions.map((action) => (

                  <div
                    key={action.title}
                    className="quick-card"
                  >

                    <div className="quick-icon">
                      {action.icon}
                    </div>

                    <span>{action.title}</span>

                  </div>

                ))}

              </div>

            </div>

            {/* Activity */}

            <div className="modern-card">

              <div className="card-title">
                Recent Activity
              </div>

              <div className="activity-list-modern">

                {activities.map((item) => (

                  <div
                    key={item.title}
                    className="activity-item-modern"
                  >

                    <div className="activity-circle">

                      {item.icon}

                    </div>

                    <div>

                      <h4>{item.title}</h4>

                      <p>{item.time}</p>

                    </div>

                  </div>

                ))}

              </div>

            </div>

          </div>

          {/* RIGHT */}

          <div className="dashboard-right">

            {/* User Card */}

            <div className="modern-card profile-summary">

              <div className="profile-big-avatar">
                {user?.name?.charAt(0)?.toUpperCase() || "U"}
              </div>

              <h2>{user?.name}</h2>

              <span className="role-pill">
                {user?.role}
              </span>

              <div className="profile-details">

                <div>

                  <strong>Email</strong>

                  <p>{user?.email}</p>

                </div>

                <div>

                  <strong>Status</strong>

                  <p className="online-status">
                    ● Active
                  </p>

                </div>

              </div>

            </div>

            {/* JWT */}

            <div className="modern-card">

              <div className="card-title">

                Security Token

              </div>

              <div className="token-modern">

                <code>
                  {token || "No Token"}
                </code>

              </div>

              <small>

                JWT stored securely in localStorage and automatically attached using Axios Interceptor.

              </small>

            </div>

          </div>

        </section>

        <ErrorMessage message={apiError} />

      </main>

    </div>
  );
}

export default Dashboard;
